import{_ as a,o as e,c as r,ae as l}from"./chunks/framework.DD8idMxO.js";const b=JSON.parse('{"title":"Skills 技术演进时间线","description":"","frontmatter":{},"headers":[],"relativePath":"radar/04-timeline.md","filePath":"radar/04-timeline.md"}'),d={name:"radar/04-timeline.md"};function h(i,t,s,o,n,c){return e(),r("div",null,[...t[0]||(t[0]=[l(`<h1 id="skills-技术演进时间线" tabindex="-1">Skills 技术演进时间线 <a class="header-anchor" href="#skills-技术演进时间线" aria-label="Permalink to &quot;Skills 技术演进时间线&quot;">​</a></h1><blockquote><p><strong>版本</strong>: v2.0 · <strong>更新日期</strong>: 2026-05-12</p><p>本时间线只收录有公开论文 / 仓库 / 产品页可验证的事件。论文以 arXiv 编号年月为准（如 2603 = 2026 年 3 月）。</p></blockquote><hr><h2 id="一、三个时代的过渡" tabindex="-1">一、三个时代的过渡 <a class="header-anchor" href="#一、三个时代的过渡" aria-label="Permalink to &quot;一、三个时代的过渡&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2023               2024                    2025                          2026</span></span>
<span class="line"><span> │                  │                       │                             │</span></span>
<span class="line"><span> ├─ API 插件时代 ───┤                       │                             │</span></span>
<span class="line"><span> │   ChatGPT        ├─ MCP 协议时代 ───────┤                             │</span></span>
<span class="line"><span> │   Plugins        │   Anthropic MCP       ├─ Skills 时代 ──────────────┤</span></span>
<span class="line"><span> │                  │                       │   生成 / 召回 / 评测密集涌现│</span></span>
<span class="line"><span> │                  │                       │                             │</span></span></code></pre></div><hr><h2 id="二、2026-年关键论文与产品" tabindex="-1">二、2026 年关键论文与产品 <a class="header-anchor" href="#二、2026-年关键论文与产品" aria-label="Permalink to &quot;二、2026 年关键论文与产品&quot;">​</a></h2><p>以 arXiv 编号为序（编号 2601 → 2604 对应 2026 年 1 - 4 月）：</p><h3 id="_2026-年-1-月" tabindex="-1">2026 年 1 月 <a class="header-anchor" href="#_2026-年-1-月" aria-label="Permalink to &quot;2026 年 1 月&quot;">​</a></h3><table tabindex="0"><thead><tr><th>编号</th><th>项目</th><th>类型</th></tr></thead><tbody><tr><td><a href="https://arxiv.org/abs/2601.10338" target="_blank" rel="noreferrer">2601.10338</a></td><td>Liu et al. <em>Agent Skills in the Wild: Security Vulnerabilities at Scale</em></td><td>安全研究 — 揭示 26.1% 社区 Skill 含漏洞</td></tr><tr><td><strong>2026-01-20</strong></td><td><strong>Vercel <a href="./tech-skills-sh.html">skills.sh</a> 上线</strong></td><td>工业 marketplace — 90K+ Skill / 19 Agent 框架</td></tr></tbody></table><h3 id="_2026-年-2-月" tabindex="-1">2026 年 2 月 <a class="header-anchor" href="#_2026-年-2-月" aria-label="Permalink to &quot;2026 年 2 月&quot;">​</a></h3><table tabindex="0"><thead><tr><th>编号</th><th>项目</th><th>类型</th></tr></thead><tbody><tr><td><a href="https://arxiv.org/abs/2602.08234" target="_blank" rel="noreferrer">2602.08234</a></td><td><a href="./tech-skillrl.html">SkillRL</a></td><td>生成 / 优化 — Skill 库与 RL 策略递归共进化</td></tr><tr><td><a href="https://arxiv.org/abs/2602.12430" target="_blank" rel="noreferrer">2602.12430</a></td><td>Xu &amp; Yan. <em>Agent Skills for LLMs: Architecture, Acquisition, Security</em></td><td>综述 — 76.3% 安全问题需跨模态检测</td></tr><tr><td><a href="https://arxiv.org/abs/2602.12670" target="_blank" rel="noreferrer">2602.12670</a></td><td><a href="./tech-skillsbench.html">SkillsBench</a></td><td>评测基准 — 7,308 轨迹 / 84 任务 / 11 领域</td></tr><tr><td><a href="https://arxiv.org/abs/2602.20867" target="_blank" rel="noreferrer">2602.20867</a></td><td>Jiang et al. <em>SoK: Agentic Skills — Beyond Tool Use in LLM Agents</em></td><td>综述 — 该领域的 canonical SoK，定义 7 阶段生命周期</td></tr></tbody></table><h3 id="_2026-年-3-月" tabindex="-1">2026 年 3 月 <a class="header-anchor" href="#_2026-年-3-月" aria-label="Permalink to &quot;2026 年 3 月&quot;">​</a></h3><table tabindex="0"><thead><tr><th>编号</th><th>项目</th><th>类型</th></tr></thead><tbody><tr><td><a href="https://arxiv.org/abs/2603.02176" target="_blank" rel="noreferrer">2603.02176</a></td><td><a href="./tech-agentskillos.html">AgentSkillOS</a></td><td>召回 / 执行 / 管理 — Capability Tree + DAG</td></tr><tr><td><a href="https://arxiv.org/abs/2603.02766" target="_blank" rel="noreferrer">2603.02766</a></td><td><a href="./tech-evoskill.html">EvoSkill</a></td><td>生成 — 三 Agent 协作 + Pareto</td></tr><tr><td><a href="https://arxiv.org/abs/2603.04448" target="_blank" rel="noreferrer">2603.04448</a></td><td><a href="./tech-skillnet.html">SkillNet</a></td><td>召回 / 评测 / 管理 — 200K+ Skill 仓库</td></tr><tr><td><a href="https://arxiv.org/abs/2603.17187" target="_blank" rel="noreferrer">2603.17187</a></td><td><a href="./tech-metaclaw.html">MetaClaw</a></td><td>优化 — 双环架构</td></tr><tr><td><a href="https://arxiv.org/abs/2603.18743" target="_blank" rel="noreferrer">2603.18743</a></td><td><a href="./tech-memento-skills.html">Memento-Skills</a></td><td>执行 / 召回 — 闭环 + 行为可训练 Router</td></tr><tr><td><a href="https://arxiv.org/abs/2603.22455" target="_blank" rel="noreferrer">2603.22455</a></td><td><a href="./tech-skillrouter.html">SkillRouter</a></td><td>召回 — 80K 池 74% Hit@1</td></tr><tr><td><a href="https://arxiv.org/abs/2603.25158" target="_blank" rel="noreferrer">2603.25158</a></td><td><a href="./tech-trace2skill.html">Trace2Skill</a></td><td>生成 — 并行轨迹蒸馏</td></tr><tr><td><a href="https://arxiv.org/abs/2603.29919" target="_blank" rel="noreferrer">2603.29919</a></td><td><a href="./tech-skillreducer.html">SkillReducer</a></td><td>优化 — less-is-more 大规模实证</td></tr></tbody></table><h3 id="_2026-年-4-月" tabindex="-1">2026 年 4 月 <a class="header-anchor" href="#_2026-年-4-月" aria-label="Permalink to &quot;2026 年 4 月&quot;">​</a></h3><table tabindex="0"><thead><tr><th>编号</th><th>项目</th><th>类型</th></tr></thead><tbody><tr><td><a href="https://arxiv.org/abs/2604.01687" target="_blank" rel="noreferrer">2604.01687</a></td><td><a href="./tech-evoskills.html">EvoSkills / CoEvoSkills</a></td><td>生成 / 评测 — Surrogate + Oracle 协同进化</td></tr><tr><td><a href="https://arxiv.org/abs/2604.04804" target="_blank" rel="noreferrer">2604.04804</a></td><td><a href="./tech-skillx.html">SkillX</a></td><td>生成 — 三层粒度蒸馏</td></tr><tr><td><a href="https://arxiv.org/abs/2604.08377" target="_blank" rel="noreferrer">2604.08377</a></td><td><a href="./tech-skillclaw.html">SkillClaw</a></td><td>优化 / 管理 — 多用户轨迹聚合</td></tr><tr><td><a href="https://arxiv.org/abs/2604.08618" target="_blank" rel="noreferrer">2604.08618</a></td><td><a href="./tech-skillforge.html">SkillForge</a></td><td>生成 / 优化 / 评测 — 工业研究（SIGIR 2026）</td></tr></tbody></table><h3 id="_2026-年-5-月" tabindex="-1">2026 年 5 月 <a class="header-anchor" href="#_2026-年-5-月" aria-label="Permalink to &quot;2026 年 5 月&quot;">​</a></h3><table tabindex="0"><thead><tr><th>编号</th><th>项目</th><th>类型</th></tr></thead><tbody><tr><td><a href="https://arxiv.org/abs/2605.03353" target="_blank" rel="noreferrer">2605.03353</a></td><td><a href="./tech-skcc.html">SkCC</a></td><td>执行 — SkIR 强类型 IR，跨框架可移植性</td></tr><tr><td><a href="https://arxiv.org/abs/2605.05726" target="_blank" rel="noreferrer">2605.05726</a></td><td><a href="./tech-skillret.html">SkillRet</a></td><td>召回 / 评测 — Skill 检索大规模 benchmark（17,810 Skill）</td></tr></tbody></table><hr><h2 id="三、非论文事件" tabindex="-1">三、非论文事件 <a class="header-anchor" href="#三、非论文事件" aria-label="Permalink to &quot;三、非论文事件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>节点</th><th>项目</th><th>内容</th></tr></thead><tbody><tr><td>持续</td><td><a href="./tech-skill-creator.html">Skill Creator</a></td><td>Anthropic 官方 Agent Skills 文档 + Claude Code 工作流</td></tr><tr><td>持续</td><td><a href="./tech-skill-seekers.html">Skill Seekers</a></td><td>社区 13.4K+ ★，18 数据源 → 20 目标</td></tr><tr><td>持续</td><td><a href="./tech-openspace.html">OpenSpace</a></td><td>HKU HKUDS · <strong>6.1K+ ★</strong> · 社区云上线</td></tr><tr><td>持续</td><td><a href="./tech-hermes-self-evolution.html">Hermes Self-Evolution</a></td><td>Nous Research · GEPA ICLR 2026 接收 · 父仓 145K+ ★</td></tr><tr><td>持续</td><td><a href="./tech-claudeception.html">Claudeception</a></td><td>社区开源 · <strong>2.3K+ ★</strong></td></tr><tr><td>持续</td><td><a href="./tech-skillrouter-org.html">SkillRouter.org</a></td><td>早期阶段 MCP 路由商业服务（落地页阶段）</td></tr><tr><td>持续</td><td><a href="./tech-skills-standard.html">agentskills.io</a></td><td>Anthropic 发起的跨平台 Skill 开放标准（~38+ 产品采用）</td></tr><tr><td>持续</td><td><a href="./tech-skills-sh.html">Vercel skills.sh</a></td><td>工业级 Skill marketplace（90K+ Skill / 19 Agent 框架）</td></tr><tr><td>持续</td><td><a href="https://owasp.org/www-project-agentic-skills-top-10/" target="_blank" rel="noreferrer">OWASP Agentic Skills Top 10</a></td><td>安全治理指南立项</td></tr></tbody></table><hr><h2 id="四、技术演进规律" tabindex="-1">四、技术演进规律 <a class="header-anchor" href="#四、技术演进规律" aria-label="Permalink to &quot;四、技术演进规律&quot;">​</a></h2><h3 id="_4-1-生成赛道-从手工到自动-从单源到多源" tabindex="-1">4.1 生成赛道：从手工到自动，从单源到多源 <a class="header-anchor" href="#_4-1-生成赛道-从手工到自动-从单源到多源" aria-label="Permalink to &quot;4.1 生成赛道：从手工到自动，从单源到多源&quot;">​</a></h3><p>2025 年的 Skill Creator 把&quot;手工写&quot;做成&quot;引导式 + Eval 闭环&quot;；2026 年 Q1 EvoSkill / Trace2Skill / EvoSkills / SkillRL 把生成路径推到&quot;从失败中自动发现&quot;、&quot;从执行轨迹蒸馏&quot;和&quot;与 RL 策略共进化&quot;。<strong>9 个生成方案密集出现在同一季度</strong>，是六大阶段中最拥挤的赛道。</p><h3 id="_4-2-优化赛道-进化框架密集涌现" tabindex="-1">4.2 优化赛道：进化框架密集涌现 <a class="header-anchor" href="#_4-2-优化赛道-进化框架密集涌现" aria-label="Permalink to &quot;4.2 优化赛道：进化框架密集涌现&quot;">​</a></h3><p>2026 年 Q1 一个季度内出现 8 个进化框架（OpenSpace / Hermes / SkillClaw / MetaClaw / EvoSkill / SkillForge / Trace2Skill / SkillRL），按&quot;进化信号从哪来&quot;分化为多条路径，但都在走向&quot;执行 → 分析 → 进化 → 验证 → 部署&quot;的闭环，<strong>正在趋同</strong>。</p><h3 id="_4-3-评测-管理赛道-被点名但无方案" tabindex="-1">4.3 评测 / 管理赛道：被点名但无方案 <a class="header-anchor" href="#_4-3-评测-管理赛道-被点名但无方案" aria-label="Permalink to &quot;4.3 评测 / 管理赛道：被点名但无方案&quot;">​</a></h3><p>2026 年 2 月 SkillsBench 量化了&quot;16/84 负增益&quot;等反共识结论、SoK 论文给出 canonical 生命周期定义；2026 年 1-2 月连续两篇安全研究揭示 26.1% 漏洞率。<strong>问题已被充分研究，但防御和过程评测工具仍接近为零</strong> —— 这是未来 6-12 个月最确定的工程机会。</p><h3 id="_4-4-执行赛道-跨框架可移植性破局" tabindex="-1">4.4 执行赛道：跨框架可移植性破局 <a class="header-anchor" href="#_4-4-执行赛道-跨框架可移植性破局" aria-label="Permalink to &quot;4.4 执行赛道：跨框架可移植性破局&quot;">​</a></h3><p>2026-05 SkCC 论文首次提出 <strong>SkIR 强类型 IR</strong>，把 Skill 语义与 Agent 框架格式解耦 —— 这填补了 Skill-insight 竞品分析中标为&quot;完全空白&quot;的&quot;跨 Agent 框架行为不一致&quot;问题。同月 SkillRet 给出 17,810 Skill 的检索 benchmark，补全了 SkillRouter 缺失的标准化评测套件。</p><hr><h2 id="五、参考资料" tabindex="-1">五、参考资料 <a class="header-anchor" href="#五、参考资料" aria-label="Permalink to &quot;五、参考资料&quot;">​</a></h2><ul><li><a href="./02-projects.html">全部 23 个真实产品</a></li><li>每个产品的论文 / 仓库链接见各 <a href="./../">tech-*.md 详情页</a></li><li>行业判断依据：Skill-insight 竞品分析文档（内部，2026-05）</li></ul>`,34)])])}const p=a(d,[["render",h]]);export{b as __pageData,p as default};
